// Match urgent forecast items with their suppliers
const forecastItems = $('Read Forecast Results1').all().map(i => i.json);
const supplierItems = $('Read Supplier Contacts').all().map(i => i.json);
const config        = $('Sub-workflow Trigger').first().json;

// Build supplier lookup: product_id + category -> supplier list
const supplierMap = {};
for (const s of supplierItems) {
  const key = `${s.product_id}||${s.category}`;
  if (!supplierMap[key]) supplierMap[key] = [];
  supplierMap[key].push(s);
}

const urgent = [];
for (const f of forecastItems) {
  const action = f.recomended_action || f.recommended_action;
  const isUrgent = action === 'stock up' || f.stockout_risk === 'high';
  if (!isUrgent) continue;

  const key = `${f.product_id}||${f.category}`;
  const suppliers = supplierMap[key] || [];
  if (suppliers.length === 0) continue;

  const preferred = suppliers.find(s => s.preferred === 'Yes') || suppliers[0];

  urgent.push({
    product_id:         f.product_id,
    category:           f.category,
    region:             f.region,
    predicted_demand:   f.predicted_demand,
    stockout_risk:      f.stockout_risk,
    recommended_action: action,
    action_detail:      f.action_detail,
    confidence:         f.confidence,
    supplier_id:        preferred.supplier_id,
    company_name:       preferred.company_name,
    contact_email:      preferred.contact_email,
    contact_phone:      preferred.contact_phone,
    lead_time_days:     preferred.lead_time_days,
    minimum_order_qty:  preferred.minimum_order_qty,
    unit_price_myr:     preferred.unit_price_myr,
    payment_terms:      preferred.payment_terms,
    runId:              config.runId,
    runAt:              config.runAt
  });
}

if (urgent.length === 0) {
  return [{ json: { skip: true, reason: 'No urgent restocking items found', wf2_status: 'skipped' } }];
}

return urgent.map(u => ({ json: { ...u, skip: false } }));

// Detect if we took the "skip" branch by checking if Should Skip?1 output indicated skip
// If the skip branch fires, we get one item with skip:true and no Parse Email Draft1 executions
const runId = $execution.id || '';

// Try to pull from the email-send path first
let emails = [];
try {
  emails = $('Parse Email Draft1').all().map(i => i.json);
} catch (e) {
  emails = [];
}

// If no emails were built, we took the skip path
if (emails.length === 0) {
  // Try to get skip reason from Should Skip?1 or Filter Already Contacted
  let skipReason = 'No new urgent items to contact';
  try {
    const filterOutput = $('Filter Already Contacted').first().json;
    if (filterOutput.skip_reason) skipReason = filterOutput.skip_reason;
    else if (filterOutput.urgent_count === 0) skipReason = 'No urgent stockout items in this run';
    else if (filterOutput.already_sent_count > 0) skipReason = `All ${filterOutput.already_sent_count} urgent items already contacted this run`;
  } catch (e) {}

  return [{ json: {
    wf2_status:          'success',
    run_id:              runId,
    completed_at:        new Date().toISOString(),
    emails_sent:         0,
    suppliers_contacted: 0,
    skipped:             true,
    skip_reason:         skipReason,
    summary_message:     `WF-2 complete: ${skipReason.toLowerCase()}. No emails sent.`
  }}];
}

// Happy path — emails were sent
const suppliersContacted = [...new Set(emails.map(e => e.company_name))];

return [{ json: {
  wf2_status:          'success',
  run_id:              runId,
  completed_at:        new Date().toISOString(),
  emails_sent:         emails.length,
  suppliers_contacted: suppliersContacted.length,
  supplier_list:       suppliersContacted,
  products_ordered:    emails.length,
  skipped:             false,
  logged_to_sheet:     true,
  summary_message:     `WF-2 complete: sent ${emails.length} supplier emails covering ${emails.length} products across ${suppliersContacted.length} suppliers.`
}}];

return $input.all().map(input => {
  const item = input.json;

  return {
    json: {
      company_name:  item.company_name,
      contact_email: item.contact_email,

      product: {
        product_id:         item.product_id,
        category:           item.category,
        region:             item.region,
        predicted_demand:   item.predicted_demand,
        confidence:         item.confidence,
        stockout_risk:      item.stockout_risk,
        recommended_action: item.recommended_action,
        action_detail:      item.action_detail
      },

      order: {
        requested_quantity: Math.max(
          parseInt(item.predicted_demand)  || 0,
          parseInt(item.minimum_order_qty) || 0
        ),
        unit_price_myr:    item.unit_price_myr,
        lead_time_days:    item.lead_time_days,
        payment_terms:     item.payment_terms,
        minimum_order_qty: item.minimum_order_qty
      },

      subject:  `Urgent Restocking Request — ${item.product_id} ${item.category} (${item.region})`,
      priority: 'high',

      supplier_id: item.supplier_id,
      runId:       item.runId,
      runAt:       item.runAt
    }
  };
});

return $('Parse Email Draft1').all().map(input => {
  const item = input.json;
  const config = $('Sub-workflow Trigger').first().json;

  return {
    json: {
      run_id:           config.runId || 'manual-run',
      run_at:           config.runAt || new Date().toISOString(),
      supplier_id:      item.supplier_id,
      company_name:     item.company_name,
      product_id:       item.product_id,
      category:         item.category,
      region:           item.region,
      email_subject:    item.email_subject,
      email_priority:   item.email_priority,
      sent_to:          item.contact_email,
      predicted_demand: item.predicted_demand,
      stockout_risk:    item.stockout_risk,
      status:           'sent'
    }
  };
});

const urgentItems = $input.all().map(i => i.json);

// Handle the skip-case short circuit from the previous node
if (urgentItems.length === 1 && urgentItems[0].skip === true) {
  return [{ json: urgentItems[0] }];
}

// Read existing log entries
const logEntries = $('Read Contact Log').all().map(i => i.json);

// Build a set of supplier+product keys that have already been contacted with status 'sent'
const alreadySent = new Set();
for (const log of logEntries) {
  if (log.status === 'sent' && log.supplier_id && log.product_id) {
    alreadySent.add(`${log.supplier_id}||${log.product_id}`);
  }
}

// Filter out urgent items that have already been contacted
const newToContact = urgentItems.filter(item => {
  const key = `${item.supplier_id}||${item.product_id}`;
  const skip = alreadySent.has(key);
  if (skip) {
    console.log(`Skipping ${item.supplier_id} / ${item.product_id} — already contacted`);
  }
  return !skip;
});

console.log(`Filtered: ${urgentItems.length} urgent → ${newToContact.length} new to contact (${urgentItems.length - newToContact.length} already sent)`);

if (newToContact.length === 0) {
  return [{ json: { 
    skip: true, 
    reason: 'All urgent suppliers already contacted in previous runs', 
    wf2_status: 'skipped_all_sent' 
  } }];
}

return newToContact.map(item => ({ json: item }));
